#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <sstream>
#include <iomanip>

class GameData {
private:
    std::string title;
    int version;
    int playerHealth;
    int playerLevel;
    std::vector<std::string> inventory;

public:
    GameData() : title("Unknown"), version(0), playerHealth(100), playerLevel(1) {}

    bool loadFromFile(const std::string& filename) {
        std::ifstream file(filename);
        if (!file.is_open()) {
            std::cout << "❌ Failed to open file: " << filename << std::endl;
            return false;
        }

        std::string line;

        // Read header
        if (std::getline(file, line)) {
            title = line;
        }

        if (std::getline(file, line)) {
            version = std::stoi(line);
        }

        if (std::getline(file, line)) {
            playerHealth = std::stoi(line);
        }

        if (std::getline(file, line)) {
            playerLevel = std::stoi(line);
        }

        // Read inventory (comma-separated)
        if (std::getline(file, line)) {
            inventory.clear();
            std::stringstream ss(line);
            std::string item;
            while (std::getline(ss, item, ',')) {
                if (!item.empty()) {
                    inventory.push_back(item);
                }
            }
        }

        file.close();
        std::cout << "✅ Loaded game data from " << filename << std::endl;
        return true;
    }

    void display() const {
        std::cout << "\n=== Game Data ===" << std::endl;
        std::cout << "Title: " << title << std::endl;
        std::cout << "Version: " << version << std::endl;
        std::cout << "Player Health: " << playerHealth << std::endl;
        std::cout << "Player Level: " << playerLevel << std::endl;
        std::cout << "Inventory: ";
        for (size_t i = 0; i < inventory.size(); i++) {
            std::cout << inventory[i];
            if (i < inventory.size() - 1) std::cout << ", ";
        }
        std::cout << std::endl;
    }
};

// Function to load high scores
bool loadHighScores(const std::string& filename) {
    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cout << "❌ No high scores found" << std::endl;
        return false;
    }

    std::cout << "\n=== High Scores ===" << std::endl;
    std::string line;
    int rank = 1;
    while (std::getline(file, line)) {
        std::stringstream ss(line);
        std::string name;
        int score;

        if (ss >> name >> score) {
            std::cout << "#" << rank << ": " << name << " - " << score << std::endl;
            rank++;
        }
    }

    file.close();
    return true;
}

int main() {
    std::cout << "=== Reading Files — Loading Game Data ===" << std::endl;

    // 1. Load game data
    GameData game;
    game.loadFromFile("savegame.txt");
    game.display();

    // 2. Load high scores
    loadHighScores("highscores.txt");

    // 3. Reading with error handling
    std::cout << "\n--- Error Handling ---" << std::endl;
    std::ifstream badFile("nonexistent.txt");
    if (badFile) {
        std::cout << "File exists" << std::endl;
        badFile.close();
    } else {
        std::cout << "❌ File not found. Using defaults." << std::endl;
    }

    // 4. Reading CSV-style data
    std::cout << "\n--- CSV-Style Data ---" << std::endl;
    std::ifstream csvFile("items.csv");
    if (csvFile.is_open()) {
        std::string line;
        while (std::getline(csvFile, line)) {
            std::stringstream ss(line);
            std::string name, type, valueStr;

            if (std::getline(ss, name, ',') && 
                std::getline(ss, type, ',') && 
                std::getline(ss, valueStr)) {
                std::cout << "Item: " << name 
                          << " (Type: " << type 
                          << ", Value: " << valueStr << ")" << std::endl;
            }
        }
        csvFile.close();
    }

    std::cout << "\n--- Reading Methods ---" << std::endl;
    std::cout << "✅ getline() — read line by line" << std::endl;
    std::cout << "✅ >> — formatted input" << std::endl;
    std::cout << "✅ stringstream — parse lines" << std::endl;

    return 0;
}

