#include <iostream>
#include <fstream>
#include <string>

struct Player {
    std::string name;
    int health;
    int attack;
    int defense;
};

int main() {
    std::cout << "=== Load Player Data ===" << std::endl;

    std::ifstream inFile("player.txt");

    if (inFile.is_open()) {
        Player player;

        std::getline(inFile, player.name);
        inFile >> player.health;
        inFile >> player.attack;
        inFile >> player.defense;

        inFile.close();

        std::cout << "\n=== Player Loaded ===" << std::endl;
        std::cout << "Name: " << player.name << std::endl;
        std::cout << "Health: " << player.health << std::endl;
        std::cout << "Attack: " << player.attack << std::endl;
        std::cout << "Defense: " << player.defense << std::endl;

    } else {
        std::cout << "❌ No save file found. Creating default..." << std::endl;

        std::ofstream outFile("player.txt");
        if (outFile.is_open()) {
            outFile << "Hero" << std::endl;
            outFile << 100 << std::endl;
            outFile << 20 << std::endl;
            outFile << 15 << std::endl;
            outFile.close();
            std::cout << "✅ Created default save file." << std::endl;
        }
    }

    return 0;
}
